  4→/**
  5→ * Custom SurrealDB v2 adapter for better-auth.
  6→ *
  7→ * Uses the project's existing Surreal connection (SDK v2) instead of creating
  8→ * its own. Field names arrive pre-mapped by the factory for configured core
  9→ * models (user/person, session, account, verification). Plugin models (OAuth
 10→ * tables) use better-auth's default camelCase naming which matches the DB schema.
 11→ *
 12→ * `findOne` returns `null` (not `undefined`) per better-auth contract —
 13→ * boundary exception to project no-null rule.
 14→ */
 15→export function surrealdbAdapter(surreal: Surreal) {
 16→  return createAdapterFactory({
 17→    config: {
 18→      adapterId: "surrealdb-v2",
 19→      adapterName: "SurrealDB v2",
 20→      usePlural: false,
 21→      supportsJSON: true,
 22→      supportsDates: true,
 23→      supportsBooleans: true,
 24→      supportsNumericIds: false,
 25→    },
 26→    adapter: ({ schema, getModelName, getFieldName }) => {
 27→      // Build FK map: { dbTableName → { dbColumnName → referencedDbTableName } }
 28→      const fkMap = new Map<string, Map<string, string>>();
 29→      for (const [defaultModel, modelDef] of Object.entries(schema)) {
 30→        const dbTable = getModelName(defaultModel);
 31→        const tableFks = new Map<string, string>();
 32→        for (const [defaultField, fieldAttr] of Object.entries(modelDef.fields)) {
 33→          if (fieldAttr.references?.field === "id") {
 34→            const dbColumn = getFieldName({ model: defaultModel, field: defaultField });
 35→            const refDbTable = getModelName(fieldAttr.references.model);
 36→            tableFks.set(dbColumn, refDbTable);
 37→          }
 38→        }
 39→        if (tableFks.size > 0) {
 40→          fkMap.set(dbTable, tableFks);
 41→        }
 42→      }
 43→
 44→      function getFkTable(table: string, field: string): string | undefined {
 45→        return fkMap.get(table)?.get(field);
 46→      }
 47→
 48→      /** Convert string FK values to RecordId for writes/where clauses. */
 49→      function toRecordId(table: string, field: string, value: unknown): unknown {
 50→        if (value === null || value === undefined) return value;
 51→        if (field === "id") return new RecordId(table, value as string);
 52→        const refTable = getFkTable(table, field);
 53→        if (refTable && typeof value === "string") return new RecordId(refTable, value);
 54→        return value;
 55→      }
 56→
 57→      /** Convert RecordId objects back to plain strings for the factory. */
 58→      function fromRecord(value: unknown): unknown {
 59→        if (value instanceof RecordId) return value.id as string;
 60→        return value;
 61→      }
 62→
 63→      function transformOutputRecord(record: Record<string, unknown>): Record<string, unknown> {
 64→        const out: Record<string, unknown> = {};
 65→        for (const [key, value] of Object.entries(record)) {
 66→          out[key] = fromRecord(value);
 67→        }
 68→        return out;
 69→      }
 70→
 71→      /** Prepare content for CREATE/UPDATE — convert FK strings to RecordId, strip `id`, omit nulls. */
 72→      function transformInputRecord(
 73→        data: Record<string, unknown>,
 74→        table: string,
 75→        stripId: boolean,
 76→      ): Record<string, unknown> {
 77→        const content: Record<string, unknown> = {};
 78→        for (const [key, value] of Object.entries(data)) {
 79→          if (stripId && key === "id") continue;
 80→          if (value === null || value === undefined) continue; // SurrealDB option<T> uses NONE (omit)
 81→          content[key] = toRecordId(table, key, value);
 82→        }
 83→        return content;
 84→      }
 85→
 86→      /** Build parameterized WHERE clause from CleanedWhere[]. */
 87→      function buildWhere(
 88→        where: CleanedWhere[],
 89→        table: string,
 90→      ): { clause: string; params: Record<string, unknown> } {
 91→        const parts: string[] = [];
 92→        const params: Record<string, unknown> = {};
 93→
 94→        for (let i = 0; i < where.length; i++) {
 95→          const w = where[i];
 96→          const paramKey = `w${i}`;
 97→          const value = toRecordId(table, w.field, w.value);
 98→          params[paramKey] = value;
 99→
100→          const connector = i > 0 ? ` ${w.connector} ` : "";
101→          let expr: string;
102→
103→          switch (w.operator) {
104→            case "eq":
105→              if (value === null) {
106→                expr = `${w.field} IS NONE`;
107→                delete params[paramKey];
108→              } else {
109→                expr = `${w.field} = $${paramKey}`;
110→              }
111→              break;
112→            case "ne":
113→              if (value === null) {
114→                expr = `${w.field} IS NOT NONE`;
115→                delete params[paramKey];
116→              } else {
117→                expr = `${w.field} != $${paramKey}`;
118→              }
119→              break;
120→            case "gt":
121→              expr = `${w.field} > $${paramKey}`;
122→              break;
123→            case "gte":
124→              expr = `${w.field} >= $${paramKey}`;
125→              break;
126→            case "lt":
127→              expr = `${w.field} < $${paramKey}`;
128→              break;
129→            case "lte":
130→              expr = `${w.field} <= $${paramKey}`;
131→              break;
132→            case "in":
133→              expr = `${w.field} IN $${paramKey}`;
134→              break;
135→            case "not_in":
136→              expr = `${w.field} NOT IN $${paramKey}`;
137→              break;
138→            case "contains":
139→              expr = `${w.field} CONTAINS $${paramKey}`;
140→              break;
141→            case "starts_with":
142→              expr = `string::starts_with(${w.field}, $${paramKey})`;
143→              break;
144→            case "ends_with":
145→              expr = `string::ends_with(${w.field}, $${paramKey})`;
146→              break;
147→            default:
148→              expr = `${w.field} = $${paramKey}`;
149→          }
150→
151→          parts.push(`${connector}${expr}`);
152→        }
153→
154→        return { clause: parts.join(""), params };
155→      }
156→
157→      return {
158→        create: async ({ model, data }) => {
159→          const table = getModelName(model);
160→          const id = data.id as string;
161→          const record = new RecordId(table, id);
162→          const content = transformInputRecord(data, table, true);
163→
164→          const [result] = await surreal.query<[Record<string, unknown>[]]>(
165→            `CREATE $record CONTENT $content RETURN AFTER;`,
166→            { record, content },
167→          );
168→
169→          if (!result?.[0]) throw new Error(`Failed to create ${table} record`);
170→          return transformOutputRecord(result[0]) as any;
171→        },
172→
173→        findOne: async ({ model, where }) => {
174→          const table = getModelName(model);
175→          const { clause, params } = buildWhere(where, table);
176→
177→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
178→            `SELECT * FROM ${table} WHERE ${clause} LIMIT 1;`,
179→            params,
180→          );
181→
182→          const row = results?.[0];
183→          if (!row) return null; // better-auth contract: null, not undefined
184→          return transformOutputRecord(row) as any;
185→        },
186→
187→        findMany: async ({ model, where, limit, sortBy, offset }) => {
188→          const table = getModelName(model);
189→          let query = `SELECT * FROM ${table}`;
190→          let params: Record<string, unknown> = {};
191→
192→          if (where && where.length > 0) {
193→            const w = buildWhere(where, table);
194→            query += ` WHERE ${w.clause}`;
195→            params = w.params;
196→          }
197→          if (sortBy) {
198→            query += ` ORDER BY ${sortBy.field} ${sortBy.direction.toUpperCase()}`;
199→          }
200→          if (limit !== undefined) {
201→            query += ` LIMIT ${Number(limit)}`;
202→          }
203→          if (offset !== undefined) {
204→            query += ` START ${Number(offset)}`;
205→          }
206→
207→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
208→            `${query};`,
209→            params,
210→          );
211→
212→          return (results ?? []).map((r) => transformOutputRecord(r)) as any[];
213→        },
214→
215→        update: async ({ model, where, update: updateData }) => {
216→          const table = getModelName(model);
217→          const { clause, params } = buildWhere(where, table);
218→          const content = transformInputRecord(updateData as Record<string, unknown>, table, true);
219→
220→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
221→            `UPDATE ${table} MERGE $content WHERE ${clause} RETURN AFTER;`,
222→            { ...params, content },
223→          );
224→
225→          const row = results?.[0];
226→          if (!row) return null;
227→          return transformOutputRecord(row) as any;
228→        },
229→
230→        updateMany: async ({ model, where, update: updateData }) => {
231→          const table = getModelName(model);
232→          const { clause, params } = buildWhere(where, table);
233→          const content = transformInputRecord(updateData as Record<string, unknown>, table, true);
234→
235→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
236→            `UPDATE ${table} MERGE $content WHERE ${clause};`,
237→            { ...params, content },
238→          );
239→
240→          return results?.length ?? 0;
241→        },
242→
243→        delete: async ({ model, where }) => {
244→          const table = getModelName(model);
245→          const { clause, params } = buildWhere(where, table);
246→          await surreal.query(`DELETE FROM ${table} WHERE ${clause};`, params);
247→        },
248→
249→        deleteMany: async ({ model, where }) => {
250→          const table = getModelName(model);
251→          const { clause, params } = buildWhere(where, table);
252→          const [results] = await surreal.query<[Record<string, unknown>[]]>(
253→            `DELETE FROM ${table} WHERE ${clause} RETURN BEFORE;`,
254→            params,
255→          );
256→          return results?.length ?? 0;
257→        },
258→
259→        count: async ({ model, where }) => {
260→          const table = getModelName(model);
261→          let query: string;
262→          let params: Record<string, unknown> = {};
263→
264→          if (where && where.length > 0) {
265→            const w = buildWhere(where, table);
266→            query = `SELECT count() FROM ${table} WHERE ${w.clause} GROUP ALL;`;
267→            params = w.params;
268→          } else {
269→            query = `SELECT count() FROM ${table} GROUP ALL;`;
270→          }
271→
272→          const [results] = await surreal.query<[Array<{ count: number }>]>(query, params);
273→          return results?.[0]?.count ?? 0;
274→        },
275→      };
276→    },
277→  });
278→}
