 26→beforeAll(async () => {
 27→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 28→  namespace = `auth_test_${runId}`;
 29→  database = `adapter_${Math.floor(Math.random() * 100000)}`;
 30→
 31→  surreal = new Surreal();
 32→  await surreal.connect(surrealUrl);
 33→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 34→
 35→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 36→  await surreal.use({ namespace });
 37→  await surreal.query(`DEFINE DATABASE ${database};`);
 38→  await surreal.use({ namespace, database });
 39→
 40→  // Apply full schema (contains all table definitions including migrations)
 41→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 42→  await surreal.query(schemaSql);
 43→
 44→  // Create better-auth instance with testUtils plugin and our adapter
 45→  auth = betterAuth({
 46→    secret: "test-secret-minimum-32-characters-long",
