  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type { AgentHandle, SpawnAgentFn } from "./spawn-agent";
  3→import type { AgentSpawnConfig } from "./agent-options";
  4→import type { ShellExec } from "./worktree-manager";
  5→import { createWorktree, removeWorktree } from "./worktree-manager";
  6→import type { AssignmentResult } from "./assignment-guard";
  7→import type { AssignmentError, OrchestratorStatus } from "./types";
  8→import { TERMINAL_ORCHESTRATOR_STATUSES } from "./types";
  9→import { startEventBridge, type SdkMessage } from "./event-bridge";
 10→import type { StreamEvent } from "../../shared/contracts";
 11→import type { StallDetectorHandle } from "./stall-detector";
 12→import { logError, logInfo, logWarn } from "../http/observability";
 13→
 14→// ---------------------------------------------------------------------------
 15→// Types — exported for tests
 16→// ---------------------------------------------------------------------------
 17→
 18→export type SessionDeps = {
 19→  surreal: Surreal;
 20→  shellExec: ShellExec;
 21→  brainBaseUrl: string;
 22→  spawnAgent?: SpawnAgentFn;
 23→};
 24→
 25→export type SessionErrorCode =
 26→  | "TASK_NOT_FOUND"
 27→  | "TASK_NOT_ASSIGNABLE"
 28→  | "AGENT_ALREADY_ACTIVE"
 29→  | "WORKSPACE_MISMATCH"
 30→  | "MISSING_TASK_ID"
 31→  | "WORKTREE_ERROR"
 32→  | "SESSION_NOT_FOUND"
 33→  | "SESSION_ERROR";
 34→
 35→export type SessionError = {
 36→  code: SessionErrorCode;
 37→  message: string;
 38→  httpStatus: number;
 39→};
 40→
 41→export type SessionResult<T> =
 42→  | { ok: true; value: T }
 43→  | { ok: false; error: SessionError };
 44→
 45→export type OrchestratorSessionResult = SessionResult<{
 46→  agentSessionId: string;
 47→  streamId: string;
 48→  worktreeBranch: string;
 49→}>;
 50→
 51→export type SessionStatusResult = SessionResult<{
 52→  orchestratorStatus: OrchestratorStatus;
 53→  worktreeBranch?: string;
 54→  worktreePath?: string;
 55→  lastEventAt?: string;
 56→  startedAt?: string;
 57→  error?: string;
 58→}>;
 59→
 60→export type AbortSessionResult = SessionResult<{
 61→  aborted: boolean;
 62→  sessionId: string;
 63→}>;
 64→
 65→export type AcceptSessionResult = SessionResult<{
 66→  accepted: boolean;
 67→  sessionId: string;
 68→}>;
 69→
 70→export type ReviewResult = SessionResult<{
 71→  taskTitle: string;
 72→  diff: import("./worktree-manager").DiffResult;
 73→  session: {
 74→    orchestratorStatus: string;
 75→    worktreeBranch?: string;
 76→    startedAt?: string;
 77→    lastEventAt?: string;
 78→    toolCallCount?: number;
 79→    filesEdited?: number;
 80→  };
 81→}>;
 82→
 83→export type RejectSessionResult = SessionResult<{
 84→  rejected: boolean;
 85→  continuing: boolean;
 86→}>;
 87→
 88→export type PromptSessionResult = SessionResult<{
 89→  delivered: boolean;
 90→}>;
 91→
 92→// ---------------------------------------------------------------------------
 93→// In-memory handle registry — maps agentSessionId to AgentHandle
 94→// ---------------------------------------------------------------------------
 95→
 96→const handleRegistry = new Map<string, AgentHandle>();
 97→
 98→// Exported for testing cleanup
 99→export function clearHandleRegistry(): void {
100→  handleRegistry.clear();
101→}
102→
103→export function getHandle(sessionId: string): AgentHandle | undefined {
104→  return handleRegistry.get(sessionId);
105→}
106→
107→// ---------------------------------------------------------------------------
108→// Event iteration — port (dependencies as function signatures)
109→// ---------------------------------------------------------------------------
110→
111→export type EventIterationDeps = {
112→  emitEvent: (streamId: string, event: StreamEvent) => void;
113→  updateSessionStatus: (
114→    sessionId: string,
115→    status: OrchestratorStatus,
116→    error?: string,
117→  ) => Promise<void>;
118→  updateLastEventAt: (sessionId: string) => Promise<void>;
119→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
120→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
121→};
122→
123→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
124→  TERMINAL_ORCHESTRATOR_STATUSES,
125→);
126→
127→/**
128→ * Iterates the SDK message stream, forwarding messages through the event
129→ * bridge. Transitions session to "active" on first message, starts stall
130→ * detection, and stops on terminal status or error.
131→ *
132→ * Returns a Promise that resolves when iteration ends (for testing).
133→ * In production, this is launched fire-and-forget.
134→ */
135→export function startEventIteration(
136→  deps: EventIterationDeps,
137→  messageStream: AsyncIterable<unknown>,
138→  streamId: string,
139→  sessionId: string,
140→): Promise<void> {
141→  const stallDetector = deps.startStallDetector(sessionId, streamId);
142→
143→  const bridge = startEventBridge(
144→    {
145→      emitEvent: deps.emitEvent,
146→      updateLastEventAt: deps.updateLastEventAt,
147→    },
148→    streamId,
149→    sessionId,
150→    stallDetector,
151→  );
152→
153→  let firstMessageReceived = false;
154→  let messageCount = 0;
155→
156→  async function iterate(): Promise<void> {
157→    logInfo("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
158→    try {
159→      for await (const rawMessage of messageStream) {
160→        messageCount++;
161→        const msg = rawMessage as SdkMessage;
162→        logInfo("orchestrator.iteration", `SDK message received (#${messageCount})`, {
163→          sessionId,
164→          messageType: msg.type,
165→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
166→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
167→        });
168→
169→        // Check if session has reached terminal status
170→        const currentStatus = await deps.getSessionStatus(sessionId);
171→        if (TERMINAL_STATUSES.has(currentStatus)) {
172→          logInfo("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
173→          break;
174→        }
175→
176→        // Transition to active on first message
177→        if (!firstMessageReceived) {
178→          firstMessageReceived = true;
179→          await deps.updateSessionStatus(sessionId, "active");
180→        }
181→
182→        // Forward through event bridge (transform + emit + stall detection)
183→        bridge.handleMessage(msg);
184→      }
185→      logInfo("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
186→      // Transition to idle when stream ends normally and agent produced output
187→      if (firstMessageReceived) {
188→        const finalStatus = await deps.getSessionStatus(sessionId);
189→        if (!TERMINAL_STATUSES.has(finalStatus)) {
190→          await deps.updateSessionStatus(sessionId, "idle");
191→        }
192→      }
193→    } catch (err) {
194→      const errorMessage = err instanceof Error ? err.message : String(err);
195→      logError("orchestrator.iteration", "Agent message stream error", err, { sessionId, streamId });
196→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
197→    } finally {
198→      if (!firstMessageReceived) {
199→        logWarn("orchestrator.iteration", "Agent stream ended with zero messages", { sessionId, streamId });
200→      }
201→      bridge.stop();
202→      handleRegistry.delete(sessionId);
203→    }
204→  }
205→
206→  return iterate();
207→}
208→
209→// ---------------------------------------------------------------------------
210→// Pure helpers
211→// ---------------------------------------------------------------------------
212→
213→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
214→  const result: Record<string, unknown> = {};
215→  for (const [key, value] of Object.entries(obj)) {
216→    if (value !== undefined) {
217→      result[key] = value;
218→    }
219→  }
220→  return result as Partial<T>;
221→}
222→
223→function sessionNotFound(sessionId: string): SessionError {
224→  return {
225→    code: "SESSION_NOT_FOUND",
226→    message: `Session not found: ${sessionId}`,
227→    httpStatus: 404,
228→  };
229→}
230→
231→function worktreeError(message: string): SessionError {
232→  return {
233→    code: "WORKTREE_ERROR",
234→    message,
235→    httpStatus: 500,
236→  };
237→}
238→
239→function fromAssignmentError(error: AssignmentError): SessionError {
240→  return {
241→    code: error.code as SessionErrorCode,
242→    message: error.message,
243→    httpStatus: error.httpStatus,
244→  };
245→}
246→
247→// ---------------------------------------------------------------------------
248→// Session row shape (DB query result)
249→// ---------------------------------------------------------------------------
250→
251→type SessionRow = {
252→  id: RecordId<"agent_session", string>;
253→  orchestrator_status?: string;
254→  worktree_branch?: string;
255→  worktree_path?: string;
256→  started_at?: string;
257→  last_event_at?: string;
258→  task_id?: RecordId<"task", string>;
259→  workspace?: RecordId<"workspace", string>;
260→  error?: string;
261→};
262→
263→type SessionLookup =
264→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
265→  | { ok: false; error: SessionError };
266→
267→async function lookupSession(
268→  surreal: Surreal,
269→  sessionId: string,
270→): Promise<SessionLookup> {
271→  const record = new RecordId("agent_session", sessionId);
272→  const session = await surreal.select<SessionRow>(record);
273→  if (!session) {
274→    return { ok: false, error: sessionNotFound(sessionId) };
275→  }
276→  if (!session.orchestrator_status) {
277→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
278→  }
279→  const status = session.orchestrator_status as OrchestratorStatus;
280→  return { ok: true, session, record, status };
281→}
282→
283→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
284→  if (!session.workspace) {
285→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
286→  }
287→  return session.workspace as RecordId<"workspace", string>;
288→}
289→
290→function generateStreamId(sessionId: string): string {
291→  return `stream-${sessionId}`;
292→}
293→
294→function slugFromTitle(title: string): string {
295→  return title
296→    .toLowerCase()
297→    .replace(/[^a-z0-9]+/g, "-")
298→    .replace(/^-|-$/g, "")
299→    .slice(0, 50);
300→}
301→
302→// ---------------------------------------------------------------------------
303→// createOrchestratorSession
304→// ---------------------------------------------------------------------------
305→
306→type CreateSessionInput = {
307→  surreal: Surreal;
308→  shellExec: ShellExec;
309→  brainBaseUrl: string;
310→  workspaceId: string;
311→  taskId: string;
312→  authToken?: string;
313→  spawnAgent?: SpawnAgentFn;
314→  validateAssignment: (
315→    surreal: Surreal,
316→    workspaceId: string,
317→    taskId: string,
