691→  }
692→
693→  // 1. Update session status to active (agent resumes work)
694→  await input.surreal.update(sessionRecord).merge({
695→    orchestrator_status: "active" as OrchestratorStatus,
696→    last_feedback: input.feedback,
697→  });
698→
699→  // 2. Return task to in_progress
700→  if (session.task_id) {
701→    await input.surreal.update(session.task_id).merge({
702→      status: "in_progress",
703→      updated_at: new Date(),
704→    });
705→  }
706→
707→  return {
708→    ok: true,
709→    value: {
710→      rejected: true,
711→      continuing: true,
712→    },
713→  };
714→}
